import { createRouter, createWebHistory } from 'vue-router'

const routes = [
  {
    path: '/',
    name: 'HomePage',
    component: () => import('../views/pages/HomePage.vue'),
    meta: { title: 'Buy Dream Web - Professional Web Design & Digital Solutions' }
  },
  {
    path: '/about',
    name: 'AboutUsPage',
    component: () => import('../views/pages/AboutUsPage.vue'),
    meta: { title: 'About Us - Buy Dream Web' }
  },
  {
    path: '/packages',
    name: 'PackagesPage',
    component: () => import('../views/pages/PackagesPage.vue'),
    meta: { title: 'Packages & Pricing - Buy Dream Web' }
  },
  {
    path: '/faq',
    name: 'FaqPage',
    component: () => import('../views/pages/FaqPage.vue'),
    meta: { title: 'FAQ - Buy Dream Web' }
  },
  {
    path: '/contact',
    name: 'ContactUsPage',
    component: () => import('../views/pages/ContactUsPage.vue'),
    meta: { title: 'Contact Us - Buy Dream Web' }
  },
  {
    path: '/website-design',
    name: 'WebsiteDesignPage',
    component: () => import('../views/pages/WebsiteDesignPage.vue'),
    meta: { title: 'Website Design Services - Buy Dream Web' }
  },
  {
    path: '/logo-design',
    name: 'LogoDesignPage',
    component: () => import('../views/pages/LogoDesignPage.vue'),
    meta: { title: 'Logo Design Services - Buy Dream Web' }
  },
  {
    path: '/brand-identity',
    name: 'BrandIdentityPage',
    component: () => import('../views/pages/BrandIdentityPage.vue'),
    meta: { title: 'Brand Identity Services - Buy Dream Web' }
  },
  {
    path: '/app-development',
    name: 'AppDevelopmentPage',
    component: () => import('../views/pages/AppDevelopmentPage.vue'),
    meta: { title: 'App Development Services - Buy Dream Web' }
  },
  {
    path: '/seo',
    name: 'SeoPage',
    component: () => import('../views/pages/SeoPage.vue'),
    meta: { title: 'SEO Services - Buy Dream Web' }
  },
  {
    path: '/digital-marketing',
    name: 'DigitalMarketingPage',
    component: () => import('../views/pages/DigitalMarketingPage.vue'),
    meta: { title: 'Digital Marketing Services - Buy Dream Web' }
  }
]

const router = createRouter({
  history: createWebHistory(process.env.BASE_URL),
  routes,
  scrollBehavior() {
    return { top: 0 }
  }
})

router.beforeEach((to, from, next) => {
  document.title = to.meta.title || 'Buy Dream Web'
  next()
})

export default router
